/* ============ Hybrid Sensing: geometri KML, subdivisi demo, Tree Registry demo ============ */
/* Sumber geometri blok: Gunung_Hejo_VarmOS.kml (WGS-84 / EPSG:4326). Batas blok TIDAK diubah.
   Cluster & petak = Demo Subdivision (dipotong valid di dalam poligon induk).
   Seluruh titik pohon = Demo Tree Registry (seeded deterministic). */

function hsParseKml(txt){
 const out=[]; const re=/<Placemark[^>]*>([\s\S]*?)<\/Placemark>/g; let m;
 while((m=re.exec(txt))){
  const nm=(m[1].match(/<name>([\s\S]*?)<\/name>/)||[])[1];
  const co=(m[1].match(/<coordinates>([\s\S]*?)<\/coordinates>/)||[])[1];
  if(!nm||!co) continue;
  const ll=co.trim().split(/\s+/).map(p=>{const [lon,lat]=p.split(",").map(Number);return [lon,lat];})
    .filter(p=>isFinite(p[0])&&isFinite(p[1]));
  if(ll.length>=4) out.push({name:nm.trim(),ll});
 }
 return out;
}

/* Luas geodesik (spherical excess dengan radius Gaussian lokal WGS-84, m²) */
function hsGeodesicAreaM2(ll){
 const rad=Math.PI/180, a=6378137, e2=0.00669437999014;
 const mLat=ll.reduce((s,p)=>s+p[1],0)/ll.length*rad;
 const s2=Math.sin(mLat)**2, W=Math.sqrt(1-e2*s2);
 const M=a*(1-e2)/(W*W*W), N=a/W, R=Math.sqrt(M*N);
 let A=0;
 for(let i=0,n=ll.length;i<n;i++){
  const [lo1,la1]=ll[i],[lo2,la2]=ll[(i+1)%n];
  A+=(lo2-lo1)*rad*(2+Math.sin(la1*rad)+Math.sin(la2*rad));
 }
 return Math.abs(A*R*R/2);
}
const hsAreaHa=(ll)=>hsGeodesicAreaM2(ll)/10000;
function hsCentroid(ll){
 let x=0,y=0,s=0;
 for(let i=0,n=ll.length;i<n;i++){
  const [x1,y1]=ll[i],[x2,y2]=ll[(i+1)%n],c=x1*y2-x2*y1;
  s+=c; x+=(x1+x2)*c; y+=(y1+y2)*c;
 }
 if(Math.abs(s)<1e-12){ x=ll.reduce((a,p)=>a+p[0],0)/ll.length; y=ll.reduce((a,p)=>a+p[1],0)/ll.length; return [x,y]; }
 return [x/(3*s),y/(3*s)];
}
function hsBbox(pts){
 let x1=1e9,y1=1e9,x2=-1e9,y2=-1e9;
 pts.forEach(([x,y])=>{ if(x<x1)x1=x; if(y<y1)y1=y; if(x>x2)x2=x; if(y>y2)y2=y; });
 return [x1,y1,x2,y2];
}
function hsPip(pt,ll){ /* point in polygon */
 let inside=false; const [x,y]=pt;
 for(let i=0,j=ll.length-1;i<ll.length;j=i++){
  const [xi,yi]=ll[i],[xj,yj]=ll[j];
  if((yi>y)!==(yj>y) && x < (xj-xi)*(y-yi)/(yj-yi)+xi) inside=!inside;
 }
 return inside;
}
/* Sutherland–Hodgman terhadap half-plane axis=0(lon)/1(lat) */
function hsClip(ll,axis,val,keepLess){
 const inside=(p)=> keepLess ? p[axis]<=val : p[axis]>=val;
 const inter=(a,b)=>{ const t=(val-a[axis])/(b[axis]-a[axis]); return axis===0?[val,a[1]+t*(b[1]-a[1])]:[a[0]+t*(b[0]-a[0]),val]; };
 let out=[];
 for(let i=0;i<ll.length;i++){
  const cur=ll[i], prev=ll[(i+ll.length-1)%ll.length];
  const ci=inside(cur), pi=inside(prev);
  if(ci){ if(!pi) out.push(inter(prev,cur)); out.push(cur); }
  else if(pi) out.push(inter(prev,cur));
 }
 return out;
}
/* PRNG deterministik */
function hsHash(s){ let h=2166136261; for(let i=0;i<s.length;i++){ h^=s.charCodeAt(i); h=Math.imul(h,16777619); } return h>>>0; }
function hsRng(seed){ let a=hsHash(String(seed)); return function(){ a|=0; a=(a+0x6D2B79F5)|0; let t=Math.imul(a^(a>>>15),1|a); t=(t+Math.imul(t^(t>>>7),61|t))^t; return ((t^(t>>>14))>>>0)/4294967296; }; }

const HS_COM_ORDER=["durian","lengkeng","alpukat","manggis","durian","petai","rambutan","jengkol","durian","lengkeng","alpukat","manggis","rambutan","petai"];
const HS_SPACING={durian:10,lengkeng:8,alpukat:8,manggis:8,petai:12,jengkol:10,rambutan:9};
const HS_VAR={durian:["Musang King","Bawor","Kane"],lengkeng:["New Crystal","Matalada"],alpukat:["Miki","Aligator"],manggis:["Wanayasa"],petai:["Lokal Unggul"],jengkol:["Lokal"],rambutan:["Binjai","Rapiah"]};
/* Petak dengan bias masalah (cerita anomali konsisten lintas-sumber) */
const HS_PROBLEM_PLOTS=["B3C1P1","B3C1P2","B4C2P1"];

function hsBuildGeo(src){
 const plAll=(typeof src==="string"?hsParseKml(src):src).filter(p=>/^Blok/i.test(p.name));
 /* Estate 4 blok. Blok 4 = poligon gabungan (eks-Blok 4 + eks-Blok 5) satu ring. */
 const blocks=plAll.map((p,i)=>{
  const id="GH-B0"+(i+1);
  const ll=p.ll.map(([lo,la])=>[+lo.toFixed(6),+la.toFixed(6)]);
  return {id,name:p.name,level:"block",parentId:"GH",ll,areaHa:+hsAreaHa(ll).toFixed(2),centroid:hsCentroid(ll),geometrySource:"KML"};
 });
 const estateLl=blocks.flatMap(b=>b.ll);
 const estate={id:"GH",name:"Gunung Hejo",level:"estate",parentId:null,ll:null,areaHa:+blocks.reduce((a,b)=>a+b.areaHa,0).toFixed(2),centroid:hsCentroid(estateLl),geometrySource:"KML"};
 const clusters=[],plots=[]; let comIdx=0;
 /* Subdivisi estimasi sebuah ring menjadi cluster+petak (dipakai aneks Blok 4) */
 const subdivide=(ring,bid,bnum,areaHa,cStart)=>{
  const bb=hsBbox(ring); const dx=bb[2]-bb[0],dy=bb[3]-bb[1];
  const axis=dx>dy?0:1; const nC=areaHa>34?3:2;
  for(let c=0;c<nC;c++){
   const lo=bb[axis===0?0:1]+(axis===0?dx:dy)*c/nC, hi=bb[axis===0?0:1]+(axis===0?dx:dy)*(c+1)/nC;
   let cll=hsClip(ring,axis,lo,false); cll=hsClip(cll,axis,hi,true);
   if(cll.length<3) continue;
   const cnum=cStart+c; const cid="B"+bnum+"C"+cnum;
   const commodity=HS_COM_ORDER[comIdx++%HS_COM_ORDER.length];
   const plantingYear=2022+((bnum+cnum)%4);
   const cu={id:cid,name:"Cluster "+cnum,code:cid,level:"cluster",parentId:bid,ll:cll.map(p=>[+p[0].toFixed(6),+p[1].toFixed(6)]),areaHa:+hsAreaHa(cll).toFixed(2),centroid:hsCentroid(cll),commodity,plantingYear,geometrySource:"Estimasi"};
   clusters.push(cu);
   const cbb=hsBbox(cll); const ax2=axis===0?1:0;
   const span=ax2===0?cbb[2]-cbb[0]:cbb[3]-cbb[1];
   const nP=Math.max(2,Math.min(4,Math.round(cu.areaHa/4.5)));
   for(let p=0;p<nP;p++){
    const plo=cbb[ax2===0?0:1]+span*p/nP, phi=cbb[ax2===0?0:1]+span*(p+1)/nP;
    let pll=hsClip(cll,ax2,plo,false); pll=hsClip(pll,ax2,phi,true);
    if(pll.length<3) continue;
    const pid="B"+bnum+"C"+cnum+"P"+(p+1);
    plots.push({id:pid,name:pid,code:pid,level:"plot",parentId:cid,blockId:bid,ll:pll.map(q=>[+q[0].toFixed(6),+q[1].toFixed(6)]),areaHa:+hsAreaHa(pll).toFixed(2),centroid:hsCentroid(pll),commodity,plantingYear,geometrySource:"Estimasi"});
   }
  }
 };
 blocks.forEach((b,bi)=>{
  const bnum=bi+1;
  const real=(typeof HS_PETAK_GEO!=="undefined")&&HS_PETAK_GEO.blocks.find(x=>x.blok===bnum);
  if(real){
   real.clusters.forEach(rc=>{
    const cid="B"+bnum+"C"+rc.cl;
    const commodity=HS_COM_ORDER[comIdx++%HS_COM_ORDER.length];
    const plantingYear=2022+((bi+rc.cl)%4);
    const cu={id:cid,name:"Cluster "+rc.cl,code:cid,level:"cluster",parentId:b.id,ll:rc.ll,extraLl:rc.extra||null,areaHa:+(rc.area).toFixed(2),centroid:rc.centroid,commodity,plantingYear,geometrySource:"KML Lapangan"};
    clusters.push(cu);
    rc.petak.forEach(rp=>{
     const pid="B"+bnum+"C"+rc.cl+"P"+rp.incr;
     plots.push({id:pid,name:pid,code:pid,level:"plot",parentId:cid,blockId:b.id,ll:rp.ll,areaHa:+(rp.area).toFixed(3),centroid:rp.centroid,commodity,plantingYear,slope:rp.slope,geometrySource:"KML Lapangan"});
    });
   });
  } else {
   subdivide(b.ll,b.id,bnum,b.areaHa,1);
  }
 });
 /* Proyeksi equirectangular ke kanvas SVG */
 const all=blocks.flatMap(b=>b.ll);
 const [lo1,la1,lo2,la2]=hsBbox(all);
 const midLa=(la1+la2)/2, kx=Math.cos(midLa*Math.PI/180);
 const wDeg=(lo2-lo1)*kx, hDeg=(la2-la1);
 const W=wDeg>hDeg?860:Math.round(860*wDeg/hDeg), H=wDeg>hDeg?Math.round(860*hDeg/wDeg):860;
 const pad=26;
 const prj=([lo,la])=>[+(pad+((lo-lo1)*kx)/wDeg*(W-2*pad)).toFixed(1),+(pad+(la2-la)/hDeg*(H-2*pad)).toFixed(1)];
 const units={GH:estate};
 [...blocks,...clusters,...plots].forEach(u=>{ u.xy=u.ll.map(prj); u.cxy=prj(u.centroid); if(u.extraLl) u.extraXy=u.extraLl.map(r=>r.map(prj)); units[u.id]=u; });
 estate.cxy=prj(estate.centroid);
 return {estate,blocks,clusters,plots,units,view:{w:W,h:H,pad},prj,bboxLL:[lo1,la1,lo2,la2],W,H};
}

/* Demo Tree Registry — grid jarak tanam + jitter, PIP, status seeded */
function hsGenTreesForPlot(plot){ return []; }
const hsTreeCache={};
function hsTrees(plotId,GEO){
 if(!hsTreeCache[plotId]){ const p=GEO.units[plotId]; hsTreeCache[plotId]=p?hsGenTreesForPlot(p):[]; }
 return hsTreeCache[plotId];
}
function hsAllTrees(GEO){ return GEO.plots.flatMap(p=>hsTrees(p.id,GEO)); }
function hsPlotStats(plotId,GEO){
 const ts=hsTrees(plotId,GEO); const by={active:0,dead:0,missing:0,replanted:0,unproductive:0};
 ts.forEach(t=>by[t.status]++);
 return {total:ts.length,...by};
}
const HS_STATUS_ID={active:"Aktif",dead:"Mati",missing:"Hilang",replanted:"Disulam",unproductive:"Tidak Produktif"};

