/* Bootstrap geometri KML — dipakai peta operasional & Hybrid Sensing */
const REG_CENSUS={"total":19801,"byBlock":{"GH-B01":{"total":6319,"active":6196,"dead":123,"missing":0,"replanted":0,"unproductive":0},"GH-B02":{"total":4321,"active":3786,"dead":535,"missing":0,"replanted":0,"unproductive":0},"GH-B03":{"total":2005,"active":1894,"dead":111,"missing":0,"replanted":0,"unproductive":0},"GH-B04":{"total":7156,"active":6934,"dead":222,"missing":0,"replanted":0,"unproductive":0}}};
const HS_GEO=hsBuildGeo(HS_BLOCK_COORDS);
/* Registry pohon = data Sensus Desember 2025 (19.801 pohon nyata). Angka per blok dari sensus. */
const hsRegistry=()=>({total:REG_CENSUS.total,by:{active:Object.values(REG_CENSUS.byBlock).reduce((a,b)=>a+b.active,0),dead:Object.values(REG_CENSUS.byBlock).reduce((a,b)=>a+b.dead,0),missing:0,replanted:0,unproductive:0},all:[]});
const _hsCnt={};
function hsCountsFor(id){
 if(!_hsCnt[id]){
  if(id==="GH"){ const by={active:0,dead:0,missing:0,replanted:0,unproductive:0}; Object.values(REG_CENSUS.byBlock).forEach(b=>{by.active+=b.active;by.dead+=b.dead;}); _hsCnt[id]={total:REG_CENSUS.total,...by}; }
  else if(REG_CENSUS.byBlock[id]){ _hsCnt[id]={...REG_CENSUS.byBlock[id]}; }
  else { /* cluster/plot id — proporsional dari blok induk (perkiraan) */
   const bid=id.slice(0,6); const b=REG_CENSUS.byBlock[bid];
   _hsCnt[id]=b?{total:0,active:0,dead:0,missing:0,replanted:0,unproductive:0}:{total:0,active:0,dead:0,missing:0,replanted:0,unproductive:0};
  }
 }
 return _hsCnt[id];
}

/* ===== Registry pohon dari data Sensus Desember 2025 ===== */
/* Peta status sensus (5 level) -> label status registry (4 level) untuk konsistensi UI */
const CEN_SC_TO_STATUS={1:"Sehat",2:"Sehat",3:"Pemantauan",4:"Sakit",5:"Mati"};
const CEN_SC_HEALTH={1:92,2:78,3:55,4:32,5:0};
const CEN_SC_LABEL={1:"Sangat Sehat",2:"Cukup Sehat",3:"Sakit Ringan",4:"Sakit Berat",5:"Mati"};
/* Adaptasi satu record sensus -> objek pohon registry yang dipakai halaman Registri & Paspor */
function cenRecToTree(r){
 return {
  id:r.id, commodity:r.com, variety:"—", block:"GH-B0"+r.b, cluster:r.cl,
  row:r.cl!=null?("C"+String(r.cl).padStart(2,"0")):"—",
  coord:r.lat+", "+r.lon, lat:r.lat, lon:r.lon,
  planted:null, source:"Sensus Desember 2025",
  status:CEN_SC_TO_STATUS[r.sc], censusLabel:CEN_SC_LABEL[r.sc], censusCode:r.sc,
  health:CEN_SC_HEALTH[r.sc], heightCm:r.h,
  lastInspection:"2025-12-27", activeCase:null, cost:null,
  history:[{d:"2025-12-27",t:"Sensus total tanaman keras — status "+CEN_SC_LABEL[r.sc],by:"Tim Sensus"}],
 };
}
