/* Pemuat registry pohon: pakai sampel dulu (instan), lalu upgrade ke 19.801 penuh dari berkas bila tersedia (PWA). */
let _regTreeCache=null,_regTreeState="idle";
function regLoadTrees(cb){
 if(_regTreeCache){ cb(_regTreeCache); return; }
 if(_regTreeState==="loading"){ setTimeout(()=>regLoadTrees(cb),300); return; }
 _regTreeState="loading";
 fetch("./registry-trees.json").then(r=>r.ok?r.json():Promise.reject()).then(j=>{
  _regTreeCache=(j.records||j).map(cenRecToTree); _regTreeState="full"; cb(_regTreeCache);
 }).catch(()=>{ _regTreeState="sample"; cb(null); });
}

/* ===== Basemap citra satelit TERSEMAT (georeferensi dari Google Earth) =====
   Screenshot Google Earth area Kebun Gununghejo, di-warp north-up & disejajarkan
   ke geometri KML (homografi ICP, median error ~5 m). Dua resolusi: HI utk desktop
   (detail maksimal), LO utk layar kecil. Tertanam sbg data URI → tampil di artifact
   & PWA, online/offline, tanpa penyedia luar. Efek: grayscale di luar estate (konteks),
   warna penuh di dalam blok (fokus). */
const HS_BASEMAP_BOUNDS={lonmin:107.40930,lonmax:107.42796,latmin:-6.68041,latmax:-6.65283};
const HS_BASEMAP_HI="data:image/jpeg;base64,";
const HS_BASEMAP_LO="data:image/jpeg;base64,";
/* Pilih resolusi berdasar lebar layar (desktop → detail maksimal) */
const HS_IS_DESKTOP=(typeof window!=="undefined" && window.innerWidth>=1024);
const HS_BASEMAP=HS_IS_DESKTOP?HS_BASEMAP_HI:HS_BASEMAP_LO;
function hsBasemapRect(){
 const b=HS_BASEMAP_BOUNDS;
 const nw=HS_GEO.prj([b.lonmin,b.latmax]), se=HS_GEO.prj([b.lonmax,b.latmin]);
 return {x:nw[0], y:nw[1], w:se[0]-nw[0], h:se[1]-nw[1]};
}
const HS_BASEMAP_RECT=hsBasemapRect();
const HS_SAT_ATTR="Citra satelit © Google Earth";

/* ===== Titik posisi 19.801 pohon (Sensus Des 2025) — tersemat terkompres =====
   Data GPS+status tiap pohon, gzip+base64 (~216KB) → didekompres saat runtime via
   DecompressionStream (tanpa pustaka). Dipakai utk: (1) titik posisi di peta saat
   zoom ke petak, (2) sumber treesData penuh utk Registri & Paspor. Bekerja di
   artifact & PWA tanpa fetch. */
const HS_TREEPTS_GZ="";
/* Dekompres base64-gzip → objek {lat0,lon0,kom,n,lat[],lon[],b[],cl[],sc[],km[],h[],id[]} */
async function hsLoadTreePoints(){
 try{
  const bin=atob(HS_TREEPTS_GZ); const bytes=new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
  const stream=new Blob([bytes]).stream().pipeThrough(new DecompressionStream("gzip"));
  const txt=await new Response(stream).text();
  return JSON.parse(txt);
 }catch(e){ return null; }
}
/* ID pohon = kode petak + T + nomor urut dalam petak (mis. B1C2P4T44). Turunan dari posisi GPS. */
function hsTreeId(D,i){
 const pc=(D.pk&&D.pk[i]>=0&&D.pkc)?D.pkc[D.pk[i]]:null;
 const seq=(D.tseq&&D.tseq[i])?D.tseq[i]:(i+1);
 return pc?(pc+"T"+seq):("GH-SENSUS-"+String(D.id[i]).padStart(5,"0"));
}
/* Rekonstruksi objek pohon (kompatibel Registri & Paspor) dari data titik index i */
function hsPtToTree(D,i){
 const lat=+(D.lat0+D.lat[i]/1e6).toFixed(6), lon=+(D.lon0+D.lon[i]/1e6).toFixed(6);
 const sc=D.sc[i], com=D.kom[D.km[i]];
 const petak=(D.pk&&D.pk[i]>=0&&D.pkc)?D.pkc[D.pk[i]]:null;
 const id=hsTreeId(D,i);
 const recordId="GH-SENSUS-"+String(D.id[i]).padStart(5,"0");
 // Cluster & petak spasial diturunkan dari kode petak (bukan cluster sensus) agar konsisten dgn ID & Peta
 const mCl=petak?petak.match(/C(\d+)/):null; const spatialCl=mCl?parseInt(mCl[1]):null;
 const mPk=petak?petak.match(/P(\d+)/):null; const spatialPk=mPk?parseInt(mPk[1]):null;
 return {
  id, recordId, seq:(D.tseq&&D.tseq[i])||null, censusCluster:D.cl[i]||null,
  commodity:com, variety:"—", block:"GH-B0"+D.b[i], cluster:spatialCl, petakNo:spatialPk,
  petak, row:spatialCl!=null?("C"+String(spatialCl).padStart(2,"0")):"—", coord:lat+", "+lon, lat, lon,
  planted:null, source:"Sensus Desember 2025",
  status:CEN_SC_TO_STATUS[sc], censusLabel:CEN_SC_LABEL[sc], censusCode:sc,
  health:CEN_SC_HEALTH[sc], heightCm:D.h[i]||null,
  lastInspection:"2025-12-27", activeCase:null, cost:null,
  history:[{d:"2025-12-27",t:"Sensus Desember 2025 — status "+CEN_SC_LABEL[sc]+", tinggi "+(D.h[i]||"—")+" cm, difoto & di-GPS",by:"Tim Sensus"}],
 };
}
/* Bangun seluruh treesData (19.801) dari data titik */
function hsPointsToTrees(D){ const a=new Array(D.n); for(let i=0;i<D.n;i++) a[i]=hsPtToTree(D,i); return a; }

