const ROLE_ICONS={"Super Admin":Settings,"Direksi":User,"Mitra Lahan":Users,"Estate Manager":Gauge,"Agronomy Head":FlaskConical,"Field Supervisor":ClipboardList,"Warehouse Officer":Warehouse,"Seedling Officer":Sprout,"Finance":Wallet};
const can=(role,act)=>{
 if(act==="verify") return ["Super Admin","Estate Manager","Agronomy Head"].includes(role);
 if(act==="createWo") return ["Super Admin","Estate Manager","Agronomy Head","Field Supervisor","Seedling Officer"].includes(role);
 if(act==="caseAction") return ["Super Admin","Agronomy Head","Estate Manager"].includes(role);
 if(act==="planEdit") return ["Super Admin","Estate Manager","Agronomy Head"].includes(role);
 if(act==="planApprove") return ["Super Admin","Estate Manager"].includes(role);
 if(act==="verifyRecommendation") return ["Super Admin","Estate Manager","Agronomy Head"].includes(role);
 if(act==="integrationAdmin") return role==="Super Admin";
 if(typeof AL_PERMS!=="undefined"&&AL_PERMS[act]) return AL_PERMS[act].includes(role);
 return true;
};

/* ============ Komponen UI dasar ============ */
const Badge=({v,className=""})=>{ const s=STATUS_STYLE[v]||{bg:"#F3F4F6",fg:"#4B5563"}; return <span className={"inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium whitespace-nowrap "+className} style={{background:s.bg,color:s.fg}}>{v}</span>; };

const Card=({title,action,children,className="",pad=true,onClick})=>(
 <div onClick={onClick} className={"bg-white rounded-lg border border-gray-200 shadow-sm "+(onClick?"cursor-pointer hover:border-green-600 ":"")+className}>
  {title ? <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100"><h3 className="text-sm font-semibold text-gray-900">{title}</h3><div className="flex items-center gap-2">{action}</div></div> : null}
  <div className={pad?"p-4":""}>{children}</div>
 </div>);

const Kpi=({label,value,sub,icon:Icon,tone="green",onClick,trend})=>{
 const tones={green:{bg:"#DCFCE7",fg:"#166534"},blue:{bg:"#DBEAFE",fg:"#1D4ED8"},amber:{bg:"#FEF3C7",fg:"#B45309"},red:{bg:"#FEE2E2",fg:"#B91C1C"},purple:{bg:"#EDE9FE",fg:"#6D28D9"},gray:{bg:"#F3F4F6",fg:"#374151"}};
 const t=tones[tone]||tones.green;
 return (
  <div onClick={onClick} className={"bg-white rounded-lg border border-gray-200 shadow-sm p-3.5 flex items-start gap-3 "+(onClick?"cursor-pointer hover:border-green-600":"")}>
   {Icon ? <div className="rounded-md p-2 shrink-0" style={{background:t.bg,color:t.fg}}><Icon size={16}/></div> : null}
   <div className="min-w-0">
    <div className="text-xs text-gray-500 truncate">{label}</div>
    <div className="text-lg font-bold text-gray-900 leading-tight flex items-center gap-1.5">{value}
     {trend!==undefined ? (trend<0 ? <span className="text-xs font-medium text-red-600 flex items-center"><TrendingDown size={12}/>{String(trend).replace(".",",")}</span> : <span className="text-xs font-medium text-green-700 flex items-center"><TrendingUp size={12}/>+{String(trend).replace(".",",")}</span>) : null}
    </div>
    {sub ? <div className="text-xs text-gray-500 truncate">{sub}</div> : null}
   </div>
  </div>);
};

const Drawer=({open,onClose,title,subtitle,children,footer,wide})=>{
 useEffect(()=>{ if(!open||typeof window==="undefined") return; const h=(e)=>{ if(e.key==="Escape"){ e.stopPropagation(); onClose&&onClose(); } }; window.addEventListener("keydown",h); return ()=>window.removeEventListener("keydown",h); },[open,onClose]);
 return !open ? null : (
 <div className="fixed inset-0 z-40">
  <div className="absolute inset-0 bg-black bg-opacity-30" onClick={onClose}/>
  <div className={"absolute right-0 top-0 h-full bg-white shadow-2xl flex flex-col "+(wide?"w-full max-w-2xl":"w-full max-w-md")}>
   <div className="flex items-start justify-between px-4 py-3 border-b border-gray-200">
    <div><div className="text-sm font-semibold text-gray-900">{title}</div>{subtitle?<div className="text-xs text-gray-500">{subtitle}</div>:null}</div>
    <button onClick={onClose} aria-label="Tutup panel" className="p-1.5 rounded-md hover:bg-gray-100 text-gray-500"><X size={16}/></button>
   </div>
   <div className="flex-1 overflow-y-auto p-4">{children}</div>
   {footer ? <div className="px-4 py-3 border-t border-gray-200 bg-gray-50 flex flex-wrap gap-2 justify-end">{footer}</div> : null}
  </div>
 </div>);
};

const Modal=({open,onClose,title,children,footer,wide})=>{
 useEffect(()=>{ if(!open||typeof window==="undefined") return; const h=(e)=>{ if(e.key==="Escape"){ e.stopPropagation(); onClose&&onClose(); } }; window.addEventListener("keydown",h); return ()=>window.removeEventListener("keydown",h); },[open,onClose]);
 return !open ? null : (
 <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
  <div className="absolute inset-0 bg-black bg-opacity-40" onClick={onClose}/>
  <div className={"relative bg-white rounded-lg shadow-2xl w-full flex flex-col max-h-full "+(wide?"max-w-3xl":"max-w-lg")}>
   <div className="flex items-center justify-between px-4 py-3 border-b border-gray-200">
    <div className="text-sm font-semibold text-gray-900">{title}</div>
    <button onClick={onClose} aria-label="Tutup dialog" className="p-1.5 rounded-md hover:bg-gray-100 text-gray-500"><X size={16}/></button>
   </div>
   <div className="p-4 overflow-y-auto">{children}</div>
   {footer ? <div className="px-4 py-3 border-t border-gray-200 bg-gray-50 flex flex-wrap gap-2 justify-end">{footer}</div> : null}
  </div>
 </div>);
};

const Btn=({children,variant="primary",className="",size="md",...p})=>{
 const base="inline-flex items-center justify-center gap-1.5 rounded-md font-medium focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-green-600 disabled:opacity-50 disabled:cursor-not-allowed ";
 const sizes={md:"px-3.5 py-2 text-sm",sm:"px-2.5 py-1.5 text-xs"};
 const variants={
  primary:"bg-green-600 text-white hover:bg-green-700",
  secondary:"bg-white border border-gray-300 text-gray-700 hover:bg-gray-50",
  danger:"bg-red-600 text-white hover:bg-red-700",
  ghost:"text-gray-600 hover:bg-gray-100",
  amber:"bg-amber-500 text-white hover:bg-amber-600",
 };
 return <button type={p.type||"button"} className={base+sizes[size]+" "+variants[variant]+" "+className} {...p}>{children}</button>;
};

const Lbl=({children})=><label className="block text-xs font-medium text-gray-600 mb-1">{children}</label>;
const Inp=(props)=><input {...props} className={"w-full border border-gray-300 rounded-md px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-green-600 "+(props.className||"")}/>;
const Sel=({options,value,onChange,className="",...p})=>(
 <select value={value} onChange={onChange} className={"border border-gray-300 rounded-md px-2.5 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-green-600 "+className} {...p}>
  {options.map(o=> Array.isArray(o) ? <option key={o[0]} value={o[0]}>{o[1]}</option> : <option key={o} value={o}>{o}</option>)}
 </select>);
const Txt=(props)=><textarea {...props} className={"w-full border border-gray-300 rounded-md px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-green-600 "+(props.className||"")}/>;

const Tabsline=({tabs,active,onChange})=>(
 <div className="flex gap-1 border-b border-gray-200 overflow-x-auto">
  {tabs.map(t=>(
   <button key={t} onClick={()=>onChange(t)} className={"px-3.5 py-2 text-sm whitespace-nowrap border-b-2 -mb-px "+(active===t?"border-green-600 text-green-700 font-semibold":"border-transparent text-gray-500 hover:text-gray-800")}>{t}</button>
  ))}
 </div>);

const KeyVal=({k,v})=>(<div className="flex justify-between gap-3 py-1.5 border-b border-gray-50 text-sm"><span className="text-gray-500">{k}</span><span className="font-medium text-gray-900 text-right">{v}</span></div>);

const Timeline=({items})=>(
 <div className="space-y-0">
  {items.length===0 ? <div className="text-sm text-gray-400">Belum ada aktivitas tercatat.</div> : items.map((it,i)=>(
   <div key={i} className="flex gap-3">
    <div className="flex flex-col items-center">
     <div className="w-2.5 h-2.5 rounded-full bg-green-600 mt-1.5 shrink-0"/>
     {i<items.length-1 ? <div className="w-px flex-1 bg-gray-200"/> : null}
    </div>
    <div className="pb-4 min-w-0">
     <div className="text-sm text-gray-900">{it.t}</div>
     <div className="text-xs text-gray-500">{fmtD(it.d)}{it.by?" • "+it.by:""}</div>
    </div>
   </div>
  ))}
 </div>);

const ProgressBar=({v,tone="#16A34A"})=>(
 <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden"><div className="h-full rounded-full" style={{width:Math.min(100,v)+"%",background:tone}}/></div>);

const EmptyState=({t,d,action})=>(
 <div className="flex flex-col items-center justify-center py-14 text-center">
  <div className="rounded-full bg-gray-100 p-3 mb-3 text-gray-400"><Info size={22}/></div>
  <div className="text-sm font-semibold text-gray-900">{t}</div>
  {d?<div className="text-sm text-gray-500 mt-1 max-w-sm">{d}</div>:null}
  {action?<div className="mt-4">{action}</div>:null}
 </div>);

const PhotoPh=({label,h="h-24"})=>(
 <div className={"rounded-md border border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 "+h}>
  <Camera size={18}/><div className="text-xs mt-1 px-2 text-center truncate w-full">{label}</div>
 </div>);

const QRBox=({text})=>{ const cells=[]; for(let i=0;i<121;i++){ const ch=text.charCodeAt(i%text.length)+i*7; if((ch%3)!==0) cells.push(i);} return (
 <svg viewBox="-0.5 -0.5 12 12" className="w-28 h-28 bg-white border border-gray-200 rounded p-1" aria-label={"QR "+text}>
  {cells.map(i=><rect key={i} x={i%11} y={Math.floor(i/11)} width="0.9" height="0.9" fill="#111827"/>)}
 </svg>);};

const T={ table:"w-full text-sm", th:"text-left text-xs font-semibold text-gray-500 uppercase tracking-wide px-3 py-2 border-b border-gray-200 whitespace-nowrap bg-gray-50", td:"px-3 py-2.5 border-b border-gray-100 text-gray-700 whitespace-nowrap", tr:"hover:bg-green-50 cursor-pointer" };

const PageHeader=({title,subtitle,actions})=>(
 <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
  <div><h1 className="text-xl font-bold text-gray-900">{title}</h1>{subtitle?<p className="text-sm text-gray-500 mt-0.5">{subtitle}</p>:null}</div>
  <div className="flex flex-wrap items-center gap-2">{actions}</div>
 </div>);

const ChartTip={contentStyle:{fontSize:12,borderRadius:8,border:"1px solid #E5E7EB"}};
const AXIS={tick:{fontSize:11,fill:"#6B7280"},axisLine:{stroke:"#E5E7EB"},tickLine:false};

/* ================= Foto pohon parametrik (dummy) =================
   "Foto" dibedakan HANYA oleh komoditas × status × pita-tinggi, jadi
   pohon dengan kombinasi sama menghasilkan gambar identik (satu foto
   mewakili semua). Deterministik, tanpa jaringan/aset. */
const COM_VIS={
 durian:{fr:"#8B9A46",leaf:"#2F7D32",fs:"spiky"},
 lengkeng:{fr:"#B5893B",leaf:"#3B8040",fs:"cluster"},
 alpukat:{fr:"#3F5E24",leaf:"#356B2E",fs:"pear"},
 manggis:{fr:"#5B2A4A",leaf:"#2E6B3A",fs:"round"},
 mangga:{fr:"#E0A81E",leaf:"#3A8040",fs:"oval"},
 petai:{fr:"#6B8E3A",leaf:"#3B7A40",fs:"pod"},
 sawo:{fr:"#7A5230",leaf:"#3A7040",fs:"oval"},
 jengkol:{fr:"#6B5A3A",leaf:"#3B7A40",fs:"round"},
 rambutan:{fr:"#C0392B",leaf:"#357A3E",fs:"spiky"},
 nangka:{fr:"#9AA83C",leaf:"#357A3E",fs:"oval"},
 jeruk:{fr:"#F39C12",leaf:"#3A8040",fs:"round"},
};
const tpTier=(status)=>{ const s=String(status||"").toLowerCase(); if(s.includes("mati"))return"mati"; if(s.includes("berat"))return"berat"; if(s.includes("ringan")||s.includes("sakit")||s.includes("pemantau"))return"ringan"; return"sehat"; };
const tpBand=(cm)=>{ if(cm==null)return 2; if(cm<60)return 0; if(cm<120)return 1; if(cm<200)return 2; return 3; };
const TP_TIER_LEAF={sehat:null,ringan:"#A7B84A",berat:"#B98F3C",mati:"#6B5637"};
const TP_BAND_LABEL=["bibit","muda","sedang","tinggi"];

function tpFruit(cx,cy,r,vis,i){
 const f=vis.fr;
 if(vis.fs==="oval"||vis.fs==="pear"||vis.fs==="pod") return <ellipse key={i} cx={cx} cy={cy} rx={r*0.7} ry={r*1.15} fill={f} stroke="rgba(0,0,0,.15)" strokeWidth="0.4"/>;
 if(vis.fs==="spiky") return <g key={i}><circle cx={cx} cy={cy} r={r} fill={f}/><circle cx={cx} cy={cy} r={r} fill="none" stroke={f} strokeWidth="1.4" strokeDasharray="0.6 1.2"/></g>;
 if(vis.fs==="cluster") return <g key={i}><circle cx={cx-r*0.5} cy={cy} r={r*0.6} fill={f}/><circle cx={cx+r*0.5} cy={cy} r={r*0.6} fill={f}/><circle cx={cx} cy={cy+r*0.4} r={r*0.6} fill={f}/></g>;
 return <circle key={i} cx={cx} cy={cy} r={r} fill={f} stroke="rgba(0,0,0,.12)" strokeWidth="0.4"/>;
}

function TreePhotoSvg({commodity,status,heightCm,view="full",className=""}){
 const vis=COM_VIS[commodity]||{fr:"#8AA043",leaf:"#3A8040",fs:"round"};
 const tier=tpTier(status), band=tpBand(heightCm);
 const dead=tier==="mati";
 const leaf=tier==="sehat"?vis.leaf:TP_TIER_LEAF[tier];
 const leafD=dead?"#5A4636":leaf; // warna kanopi utama
 const sky="#EAF1F6", ground=dead?"#CFC7B3":"#D7DEC7";
 const trunkCol=dead?"#6E5B48":"#6B4A2B";
 const wrap=(kids)=><svg viewBox="0 0 100 100" preserveAspectRatio="xMidYMid slice" className={className} style={{display:"block"}} role="img" aria-label={"Foto "+comName(commodity)+" ("+status+")"}>{kids}</svg>;

 if(view==="batang"){ // closeup batang/kulit kayu
  const bark=dead?"#6E5B48":"#6B4A2B";
  return wrap(<g>
   <rect x="0" y="0" width="100" height="100" fill="#E7EAE0"/>
   <rect x="26" y="0" width="48" height="100" fill={bark}/>
   <rect x="26" y="0" width="10" height="100" fill="rgba(255,255,255,.08)"/>
   <rect x="64" y="0" width="10" height="100" fill="rgba(0,0,0,.15)"/>
   {[18,40,63,85].map((y,i)=><path key={i} d={"M28 "+y+" q10 6 20 0 t20 0"} stroke={dead?"#4A3A2C":"#54402C"} strokeWidth="1.2" fill="none" opacity="0.6"/>)}
   {[34,52,70].map((x,i)=><line key={i} x1={x} y1="4" x2={x+(i%2?3:-3)} y2="96" stroke="rgba(0,0,0,.18)" strokeWidth="0.8"/>)}
   {!dead&&tier==="sehat"&&[[30,72],[70,20],[32,44]].map(([x,y],i)=><circle key={i} cx={x} cy={y} r="3" fill="#5C8A3A" opacity="0.7"/>)}
   {dead&&[[40,30],[60,58]].map(([x,y],i)=><path key={i} d={"M"+x+" "+y+" l6 10 l-3 2 z"} fill="#3A2C20" opacity="0.7"/>)}
  </g>);
 }

 if(view==="piringan"){ // piringan/pendangiran (tampak atas pangkal)
  return wrap(<g>
   <rect x="0" y="0" width="100" height="100" fill={dead?"#CFC7B3":"#C9B79A"}/>
   <circle cx="50" cy="50" r="42" fill={dead?"#C4BBA4":"#BCA87F"}/>
   <circle cx="50" cy="50" r="30" fill={dead?"#B7AE95":"#A98F63"}/>
   <circle cx="50" cy="50" r="30" fill="none" stroke="#8B6F47" strokeWidth="2"/>
   <circle cx="50" cy="50" r="12" fill={trunkCol}/>
   <circle cx="50" cy="50" r="12" fill="none" stroke="rgba(0,0,0,.25)" strokeWidth="1.5"/>
   <circle cx="50" cy="50" r="7" fill="none" stroke="rgba(0,0,0,.2)" strokeWidth="1"/>
   {!dead&&(tier==="sehat"||tier==="ringan")&&[[26,34],[74,30],[30,70],[72,72],[50,22],[22,54]].slice(0,tier==="sehat"?6:3).map(([x,y],i)=><g key={i}><path d={"M"+x+" "+y+" q2 -6 4 0"} stroke="#5C8A3A" strokeWidth="1.4" fill="none"/><path d={"M"+(x+2)+" "+y+" q2 -5 4 1"} stroke="#6B9A44" strokeWidth="1.4" fill="none"/></g>)}
  </g>);
 }

 // ----- kanopi / full: bangun pohon -----
 const cx=50, groundY=86;
 const trunkH=[20,30,42,54][band], topY=groundY-trunkH, sc=[0.72,0.86,1.0,1.12][band];
 const R=21*sc, cyC=topY-R*0.45;
 const nFruit=dead?0:(tier==="sehat"?6:tier==="ringan"?4:2);
 const fruitPos=[[-0.34,0.12],[0.34,-0.02],[0.02,0.4],[-0.55,-0.24],[0.5,-0.18],[0.0,-0.34],[0.14,0.56]];
 const blobs=[[0,0,1.0],[-0.62,0.2,0.74],[0.62,0.2,0.74],[-0.36,-0.5,0.66],[0.36,-0.5,0.66],[0,0.52,0.8]];

 if(view==="kanopi"){ // closeup kanopi (zoom daun+buah)
  const RC=46;
  return wrap(<g>
   <rect x="0" y="0" width="100" height="100" fill={sky}/>
   {dead
    ? [[50,50,1],[30,40,0.7],[70,45,0.7],[42,68,0.6]].map(([x,y,s],i)=><g key={i} stroke="#6E5B48" strokeWidth={3*s} fill="none"><path d={"M"+x+" "+y+" l"+18*s+" -12"}/><path d={"M"+x+" "+y+" l-"+16*s+" -8"}/><path d={"M"+x+" "+y+" l4 -20"}/></g>)
    : <g>
       {[[50,50,RC],[26,44,RC*0.6],[74,46,RC*0.6],[38,74,RC*0.55],[66,72,RC*0.55],[50,26,RC*0.5]].map(([x,y,r],i)=><circle key={i} cx={x} cy={y} r={r} fill={leafD} opacity={i===0?1:0.92}/>)}
       {tier!=="sehat"&&[[34,40],[66,58],[50,72]].map(([x,y],i)=><circle key={i} cx={x} cy={y} r={tier==="berat"?12:8} fill={tier==="berat"?"#9C7A34":"#C7C24A"} opacity="0.7"/>)}
       {[[30,34],[70,36],[44,54],[62,66],[36,66]].map(([x,y],i)=><path key={i} d={"M"+x+" "+y+" q6 -8 12 0"} stroke="rgba(255,255,255,.25)" strokeWidth="1" fill="none"/>)}
       {(tier==="sehat"?[[36,44],[64,42],[50,60],[30,62],[70,64],[50,30]]:tier==="ringan"?[[40,46],[62,54],[50,64]]:[[48,52]]).map(([x,y],i)=>tpFruit(x,y,6.5,vis,i))}
      </g>}
  </g>);
 }

 // ----- full -----
 return wrap(<g>
  <defs><linearGradient id="tpsky" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stopColor="#E4EEF5"/><stop offset="1" stopColor="#F4F8FA"/></linearGradient></defs>
  <rect x="0" y="0" width="100" height="100" fill="url(#tpsky)"/>
  <circle cx="82" cy="18" r="8" fill="#FCE9AE" opacity="0.7"/>
  <path d={"M0 "+groundY+" q50 -8 100 0 v"+(100-groundY)+" H0 Z"} fill={ground}/>
  <path d={"M0 "+(groundY+4)+" q50 -6 100 0"} stroke="rgba(0,0,0,.06)" strokeWidth="1" fill="none"/>
  {/* bayangan */}
  <ellipse cx={cx} cy={groundY+3} rx={R*0.9} ry="3.5" fill="rgba(0,0,0,.12)"/>
  {/* batang */}
  <rect x={cx-2.6*sc} y={topY} width={5.2*sc} height={trunkH+2} rx={1.6} fill={trunkCol}/>
  <rect x={cx-2.6*sc} y={topY} width={2*sc} height={trunkH+2} rx={1} fill="rgba(255,255,255,.1)"/>
  {dead ? <g stroke={trunkCol} strokeWidth={2.4*sc} fill="none" strokeLinecap="round">
    <path d={"M"+cx+" "+topY+" l"+(-10*sc)+" "+(-8*sc)}/><path d={"M"+cx+" "+(topY+4)+" l"+(11*sc)+" "+(-6*sc)}/><path d={"M"+cx+" "+topY+" l"+(2*sc)+" "+(-14*sc)}/>
    <path d={"M"+(cx-8*sc)+" "+(topY-8*sc)+" l"+(-5*sc)+" "+(-4*sc)}/><path d={"M"+(cx+10*sc)+" "+(topY-5*sc)+" l"+(5*sc)+" "+(-5*sc)}/>
   </g> : <g>
    {/* kanopi */}
    {blobs.map(([dx,dy,r],i)=><circle key={i} cx={cx+dx*R} cy={cyC+dy*R} r={R*r} fill={leafD} opacity={i===0?1:0.94}/>)}
    <circle cx={cx-R*0.3} cy={cyC-R*0.3} r={R*0.5} fill="rgba(255,255,255,.14)"/>
    {tier!=="sehat"&&[[-0.3,0.2],[0.35,-0.1],[0.05,0.45]].slice(0,tier==="berat"?3:2).map(([dx,dy],i)=><circle key={i} cx={cx+dx*R} cy={cyC+dy*R} r={R*(tier==="berat"?0.4:0.28)} fill={tier==="berat"?"#9C7A34":"#C7C24A"} opacity="0.75"/>)}
    {fruitPos.slice(0,nFruit).map(([dx,dy],i)=>tpFruit(cx+dx*R,cyC+dy*R,2.6*sc+1,vis,i))}
   </g>}
 </g>);
}

/* ===== Foto ASLI (Creative Commons via LoremFlickr) — dimuat runtime, deterministik per kombinasi ===== */
const TP_KW={
 durian:"durian,fruit,tree", lengkeng:"longan,fruit", alpukat:"avocado,tree,fruit",
 manggis:"mangosteen,fruit", mangga:"mango,tree,fruit", petai:"parkia,petai,beans",
 sawo:"sapodilla,fruit,tree", jengkol:"jengkol,archidendron", rambutan:"rambutan,fruit",
 nangka:"jackfruit,tree", jeruk:"orange,citrus,tree",
};
const tpSeed=(s)=>{ let h=2166136261; for(let i=0;i<s.length;i++){ h^=s.charCodeAt(i); h=Math.imul(h,16777619);} return (h>>>0)%99991+1; };
function tpPhotoUrl(commodity,status,heightCm,view){
 const tier=tpTier(status), band=tpBand(heightCm);
 const base=TP_KW[commodity]||"tropical,fruit,tree";
 let kw = view==="batang" ? "tree,trunk,bark" : view==="piringan" ? "tree,soil,base,roots" : view==="kanopi" ? base+",leaves,canopy" : base;
 if(tier==="mati" && (view==="full"||view==="kanopi")) kw = "dead,tree,dry,trunk";
 const seed=tpSeed(commodity+"|"+tier+"|"+band+"|"+view);
 return "https://loremflickr.com/480/360/"+kw.replace(/\s+/g,",")+"?lock="+seed;
}
/* Coba foto asli dulu; jika gagal / offline, fallback ke ilustrasi SVG parametrik. */
function TreePhoto(props){
 const [failed,setFailed]=useState(false);
 const url=tpPhotoUrl(props.commodity,props.status,props.heightCm,props.view||"full");
 if(failed||!url) return <TreePhotoSvg {...props}/>;
 return <img src={url} alt={"Foto "+comName(props.commodity)+" — "+(props.status||"")} loading="lazy" onError={()=>setFailed(true)}
  className={(props.className||"")+" object-cover bg-gray-100"} style={{display:"block"}}/>;
}

/* ============ Shell: Sidebar, TopNav, Command Palette, Login ============ */
function Sidebar(){
 const {role,route,nav,collapsed,setCollapsed,counts,setRole,logout}=useApp();
 const hide=ROLES[role].hide;
 const [open,setOpen]=useState({"g-dash":true,"g-ops":true,"g-agro":false,"g-plant":false,"g-res":false});
 const badgeVal=(b)=> b==="wo"?counts.wo : b==="verif"?counts.verif : b==="alerts"?counts.alerts : b==="dq"?counts.dq : b==="ai"?(counts.ai||0) : b==="field"?(counts.field||0) : 0;
 const visibleChildren=(item)=> (item.children||[]).filter(c=>!hide.includes(c.page));
 const isActive=(p)=> route.page===p || (p==="workorders"&&["wo","wo-new"].includes(route.page)) || (p==="trees"&&route.page==="tree") || (p==="health"&&route.page==="case") || (p==="map"&&route.page==="block") || (p==="dq-issues"&&route.page==="dq-issue");
 return (
  <aside className={"h-full bg-white border-r border-gray-200 flex flex-col shrink-0 transition-all "+(collapsed?"w-16":"w-64")}>
   <div className="px-3 py-3 border-b border-gray-200">
    <div className="flex items-center gap-2.5">
     <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0" style={{background:C.dark}}><Leaf size={18} className="text-white"/></div>
     {!collapsed && <div className="min-w-0">
      <div className="text-sm font-bold text-gray-900 leading-tight">VarmOS Plantation</div>
      <div className="text-xs text-gray-500 truncate">Command Center</div>
     </div>}
    </div>
    {!collapsed && <select aria-label="Pilih estate" className="mt-2.5 w-full text-xs border border-gray-200 rounded-md px-2 py-1.5 bg-gray-50 text-gray-700" value="EST-001" onChange={()=>{}}>
     <option value="EST-001">Kebun Agroforestry Gununghejo</option>
    </select>}
   </div>
   <nav className="flex-1 overflow-y-auto py-2 px-2 space-y-0.5">
    {NAV.map(item=>{
     if(item.children){
      const kids=visibleChildren(item);
      if(kids.length===0) return null;
      const anyActive=kids.some(k=>isActive(k.page));
      return (
       <div key={item.id}>
        <button onClick={()=> collapsed ? nav(kids[0].page) : setOpen(o=>({...o,[item.id]:!o[item.id]}))}
          className={"w-full flex items-center gap-2.5 px-2.5 py-2 rounded-md text-sm "+(anyActive?"text-green-800 bg-green-50 font-semibold":"text-gray-700 hover:bg-gray-50")}>
         <item.icon size={17} className="shrink-0"/>
         {!collapsed && <><span className="flex-1 text-left truncate">{item.label}</span><ChevronDown size={14} className={"transition-transform "+(open[item.id]?"":"-rotate-90")}/></>}
        </button>
        {!collapsed && open[item.id] && <div className="ml-6 mt-0.5 space-y-0.5">
         {kids.map(k=>{
          const bv=k.badge?badgeVal(k.badge):0;
          return (
          <button key={k.page} onClick={()=>nav(k.page)} className={"w-full flex items-center justify-between px-2.5 py-1.5 rounded-md text-sm "+(isActive(k.page)?"bg-green-100 text-green-800 font-semibold":"text-gray-600 hover:bg-gray-50")}>
           <span className="truncate">{k.label}</span>
           {bv>0 ? <span className="text-xs font-semibold px-1.5 py-0.5 rounded-full" style={{background: ["alerts","dq"].includes(k.badge)?"#FEE2E2":"#DBEAFE", color:["alerts","dq"].includes(k.badge)?"#B91C1C":"#1D4ED8"}}>{bv}</span> : null}
          </button>);
         })}
        </div>}
       </div>);
     }
     if(hide.includes(item.page)) return null;
     const bv=item.badge?badgeVal(item.badge):0;
     return (
      <button key={item.id} onClick={()=>nav(item.page)} className={"w-full flex items-center gap-2.5 px-2.5 py-2 rounded-md text-sm "+(isActive(item.page)?"bg-green-100 text-green-800 font-semibold":"text-gray-700 hover:bg-gray-50")}>
       <item.icon size={17} className="shrink-0"/>
       {!collapsed && <span className="flex-1 text-left truncate">{item.label}</span>}
       {!collapsed && bv>0 ? <span className="text-xs font-semibold px-1.5 py-0.5 rounded-full" style={{background:"#FEE2E2",color:"#B91C1C"}}>{bv}</span> : null}
      </button>);
    })}
   </nav>
   <div className="border-t border-gray-200 p-2 space-y-1">
    <button onClick={()=>setCollapsed(!collapsed)} className="w-full flex items-center gap-2.5 px-2.5 py-2 rounded-md text-sm text-gray-600 hover:bg-gray-50">
     {collapsed?<ChevronRight size={17}/>:<ChevronLeft size={17}/>}{!collapsed && "Ciutkan menu"}
    </button>
    <button onClick={()=>{logout();nav("login");}} className="w-full flex items-center gap-2.5 px-2.5 py-2 rounded-md text-sm text-gray-600 hover:bg-gray-50">
     <LogOut size={17}/>{!collapsed && "Keluar"}
    </button>
   </div>
  </aside>);
}

