  action:{type:"wo",wo:{title:"Servis nozzle 2 unit Sprayer Punggung (EQ-01) — kesiapan aplikasi November",activity:"Perbaikan irigasi",block:"GH-B04",sop:"SOP-UMU-05",scheduled:"2026-10-05",due:"2026-10-16",team:2}},
