  attribution:[{f:"Tren NDVI 14 hari: −0,09",val:0.31},{f:"Curah hujan kumulatif 7 hari: 142 mm",val:0.24},{f:"Kelembapan tanah 63% (data 3 hari — konektor degraded)",val:0.12},{f:"Riwayat kasus blok 90 hari: 1 kasus",val:0.07}],
